# ── Cache helpers ─────────────────────────────────────────────────────

def _cache_path(namespace, key):
    """~/.hermes/cache/<namespace>/<sha1(key)>.json. Creates namespace dir."""
    d = CACHE_ROOT / namespace
    d.mkdir(parents=True, exist_ok=True)
    return d / (hashlib.sha1(str(key).encode("utf-8")).hexdigest() + ".json")


def _cache_get(namespace, key):
    """Return cached dict or None. Silently treats corrupt cache as a miss."""
    p = _cache_path(namespace, key)
    if not p.exists():
        return None
    try:
        with open(p, "r", encoding="utf-8") as f:
            return json.load(f)
    except (OSError, ValueError):
        return None


def _cache_put(namespace, key, payload):
    """Write payload to cache. Silent on OSError — cache is best-effort."""
    p = _cache_path(namespace, key)
    try:
        with open(p, "w", encoding="utf-8") as f:
            json.dump(payload, f)
    except OSError:
        pass


# ── Auth ──────────────────────────────────────────────────────────────

def _api_key():
    """Read DATA_GOV_SG_API_KEY at call time. None when unset."""
    return os.environ.get("DATA_GOV_SG_API_KEY") or None


def require_api_key():
    """Raise a clear error if DATA_GOV_SG_API_KEY is not set. Call this at
    startup for skills that need v2 data (e.g. S04a mrt-rerouter for MRT
    arrival times, which v1 does not publish)."""
    if not _api_key():
        raise RuntimeError(
            "DATA_GOV_SG_API_KEY is not set. Register at https://data.gov.sg/ "
            "to get a key. Some data sources (MRT train arrival) require it."
        )


# ── Core: request_json ────────────────────────────────────────────────

def _do_request(url, headers, namespace, cache_key):
    """Single HTTP attempt. Returns parsed JSON or raises HTTPError/URLError."""
    cached = _cache_get(namespace, cache_key)
    if cached is not None:
        return cached

    last_err = None
    for attempt in range(MAX_ATTEMPTS):
        if attempt > 0:
            time.sleep(BACKOFF_S[attempt - 1])
        try:
            req = urllib.request.Request(url, headers=headers)
            with urllib.request.urlopen(req, timeout=TIMEOUT_S) as resp:
                raw = resp.read()
                if resp.headers.get("Content-Encoding") == "gzip":
                    raw = gzip.decompress(raw)
                body = json.loads(raw)
                _cache_put(namespace, cache_key, body)
                return body
        except urllib.error.HTTPError as e:
            last_err = e
            if e.code == 429 or e.code >= 500:
                continue  # retry
            raise  # 4xx other than 429 → fail fast
        except (urllib.error.URLError, TimeoutError, json.JSONDecodeError) as e:
            last_err = e
            continue  # network/parse → retry

    raise last_err if last_err else RuntimeError("request_json: retries exhausted")


def request_json(url, params=None, namespace=None, extra_headers=None):
    """
    Fetch a JSON payload with auth, caching, retry, and timeout.

    - Cache hit → return immediately, no network.
    - 200 → parse JSON, write to cache, return.
    - 429 / 5xx → retry up to MAX_ATTEMPTS with BACKOFF_S sleeps.
    - Other 4xx → raise urllib.error.HTTPError immediately.
    - Network errors (URLError, TimeoutError, JSONDecodeError) → retry.
    - Raises the last exception after exhausting retries.
    """
    qs = urllib.parse.urlencode(params or {})
    full_url = url + ("?" + qs if qs else "")
    cache_ns = namespace or "default"
    cache_key = full_url

    headers = {
        "Accept-Encoding": "gzip",
        "User-Agent": USER_AGENT,
    }
    key = _api_key()
    if key:
        headers["x-api-key"] = key
    if extra_headers:
        headers.update(extra_headers)

    return _do_request(full_url, headers, cache_ns, cache_key)


def try_v2_then_v1(v1_path, params=None, namespace=None, extra_headers=None):
    """
    Try v2 first (when DATA_GOV_SG_API_KEY is set), fall back to v1 on
    401/404/5xx. Both versions are cached separately.

    Use this for endpoints that exist in both v1 and v2 (most real-time
    environment + transport data). v1-only or v2-only endpoints should call
    request_json() directly.
    """
    cache_ns = namespace or "default"
    key = _api_key()
    v2_endpoint = _V1_TO_V2.get(v1_path)

    qs = urllib.parse.urlencode(params or {})
    headers = {
        "Accept-Encoding": "gzip",
        "User-Agent": USER_AGENT,
    }
    if key:
        headers["x-api-key"] = key
    if extra_headers:
        headers.update(extra_headers)

    # 1) v2 with key
    if key and v2_endpoint:
        v2_url = DATA_GOV_V2 + "/" + v2_endpoint + ("?" + qs if qs else "")
        try:
            return _do_request(v2_url, headers, cache_ns, "v2|" + v2_url)
        except urllib.error.HTTPError as e:
            if e.code not in (401, 403, 404):
                # 5xx or 429: tried MAX_ATTEMPTS times, give up on v2 → fall through to v1
                pass  # fall through to v1
            # 401/403/404: key not authorised, or endpoint not in v2 → fall through to v1
        except (urllib.error.URLError, TimeoutError):
            pass  # network error → fall through to v1

    # 2) v1 fallback
    v1_url = DATA_GOV_V1 + v1_path + ("?" + qs if qs else "")
    # Strip the key header for v1 (v1 doesn't need it; cleaner logs)
    v1_headers = {k: v for k, v in headers.items() if k.lower() != "x-api-key"}
    return _do_request(v1_url, v1_headers, cache_ns, "v1|" + v1_url)


# ── v1 envelope normalisation ─────────────────────────────────────────
# v1 returns nested envelopes (items[].cameras[], items[].carpark_data[].carpark_info[],
# items[].forecasts[]). Skill scripts expect a flat items[] shape, so each
# fetcher that uses v1 normalises before returning. v2 generally returns flat
# shapes already, so v2-fallback callers should not need to re-normalise.

def _flatten_v1_traffic_images(envelope):
    """v1: {items: [{cameras: [{camera_id, image, location, ...}]}]}
    → flat: {items: [{camera_id, image, latitude, longitude, name, timestamp}]}"""
    if not isinstance(envelope, dict):
        return {"items": []}
    flat = []
    for bucket in envelope.get("items") or []:
        for cam in bucket.get("cameras") or []:
            loc = cam.get("location") or {}
            flat.append({
                "camera_id": cam.get("camera_id"),
                "image": cam.get("image"),
                "latitude": loc.get("latitude"),
                "longitude": loc.get("longitude"),
                "name": cam.get("camera_id"),  # v1 has no human label; id is the handle
                "timestamp": cam.get("timestamp"),
            })
    return {"items": flat}


def _flatten_v1_carpark_availability(envelope):
    """v1: {items: [{carpark_data: [{carpark_number, carpark_info: [{lots_available, lot_type, total_lots}]}]}]}
    → flat: {items: [{carpark_id, lots_available, lot_type, total_lots, agency: 'HDB', update_datetime}]}.
    `lots_available` and `total_lots` are strings in v1; coerced to int."""
    if not isinstance(envelope, dict):
        return {"items": []}
    flat = []
    for bucket in envelope.get("items") or []:
        for cd in bucket.get("carpark_data") or []:
            for info in cd.get("carpark_info") or []:
                try:
                    lots = int(info.get("lots_available") or 0)
                except (TypeError, ValueError):
                    lots = 0
                try:
                    total = int(info.get("total_lots") or 0)
                except (TypeError, ValueError):
                    total = 0
                flat.append({
                    "carpark_id": cd.get("carpark_number"),
                    "lots_available": lots,
                    "lot_type": info.get("lot_type"),
                    "total_lots": total,
                    "agency": "HDB",  # v1's carpark-availability is HDB-only
                    "update_datetime": cd.get("update_datetime"),
                })
    return {"items": flat}


def _flatten_v1_two_hour_forecast(envelope):
    """v1: {items: [{forecasts: [{area, forecast}], valid_period, ...}], area_metadata: [...]}
    → flat: {items: [{area, forecast}], valid_period, update_timestamp, area_metadata}.
    Keeps `area_metadata` so callers can geocode an area name if needed."""
    if not isinstance(envelope, dict):
        return {"items": []}
    out = {"items": [], "area_metadata": envelope.get("area_metadata") or []}
    for bucket in envelope.get("items") or []:
        out["items"].extend(bucket.get("forecasts") or [])
        if "valid_period" in bucket and "valid_period" not in out:
            out["valid_period"] = bucket["valid_period"]
        if "update_timestamp" in bucket and "update_timestamp" not in out:
            out["update_timestamp"] = bucket["update_timestamp"]
    return out


