def fetch_lta_bus_arrival(bus_stop_code=None, service_no=None):
    """LTA bus arrival times. v2 takes BusStopCode + ServiceNo as query params.
    When called without args, fetches a generic list (may 400 on v1; v2 is more
    forgiving). S04a (mrt-rerouter) parameterises this directly."""
    params = {}
    if bus_stop_code:
        params["BusStopCode"] = bus_stop_code
    if service_no:
        params["ServiceNo"] = service_no
    return try_v2_then_v1("/transport/bus-eta", params=params, namespace="bus-arrival")


def fetch_lta_mrt_arrival(station_code=None):
    """LTA MRT train arrival times. v2-only (v1 does not publish MRT data);
    DATA_GOV_SG_API_KEY is required. Callers that need MRT data should check
    the env var first or catch the RuntimeError raised when the key is missing.

    `station_code` (e.g. 'NS1' for Marina South Pier) is passed as a query
    param when set.
    """
    require_api_key()
    params = {}
    if station_code:
        params["StationCode"] = station_code
    qs = urllib.parse.urlencode(params)
    url = DATA_GOV_V2 + "/mrt-train-arrival" + ("?" + qs if qs else "")
    headers = {
        "Accept-Encoding": "gzip",
        "User-Agent": USER_AGENT,
        "x-api-key": _api_key(),
    }
    return _do_request(url, headers, "mrt-arrival", "v2|" + url)


def fetch_lta_taxi_availability():
    """LTA taxi availability by zone (GeoJSON-style coordinates)."""
    return try_v2_then_v1("/transport/taxi-availability", namespace="taxi-availability")


# ── CKAN datastore helpers (static datasets) ──────────────────────────
# Most non-real-time data.gov.sg datasets are served via the CKAN
# `datastore_search` action on a separate host (no /v1, no /v2, no auth).
# Each call paginates with limit+offset; total count comes back as
# result.total. The resource_id (UUID) is dataset-specific — discover via
# `https://data.gov.sg/api/action/package_show?id=<name>` and pick the
# resource where `datastore_active` is true.

def fetch_datastore_search(resource_id, limit=100, offset=0, filters=None):
    """Legacy CKAN stub. data.gov.sg no longer uses CKAN. See
    fetch_dataset_rows() / fetch_dataset_geojson() for the v2 download flow.
    """
    raise NotImplementedError("CKAN deprecated; use fetch_dataset_rows")


def _dataset_headers():
    """Headers required by data.gov.sg initiate-download and poll-download.
    Verified live: missing either header → HTTP 403. The x-api-key value comes
    from the DATA_GOV_SG_API_KEY env var (v2 key, registered at data.gov.sg).
    """
    h = {
        "User-Agent": USER_AGENT,
        "Content-Type": "application/json",
    }
    key = os.environ.get("DATA_GOV_SG_API_KEY")
    if key:
        h["x-api-key"] = key
    return h


def fetch_dataset_rows(dataset_id, filters=None):
    """Generic data.gov.sg dataset fetch (CSV → list of row dicts).

    Flow:
      1. POST initiate-download (best-effort, swallow auth errors)
      2. GET poll-download → signed S3 URL
      3. GET the URL → CSV body
      4. Parse with csv.DictReader, return list[dict]
    """
    import csv as _csv
    import io as _io

    namespace = "dataset:%s" % dataset_id
    if filters:
        import hashlib
        key = repr(filters) if isinstance(filters, (list, tuple)) else repr(sorted(filters.items()))
        h = hashlib.sha1(key.encode("utf-8")).hexdigest()[:12]
        namespace = "dataset:%s:%s" % (dataset_id, h)

    cached = _cache_get(namespace, "rows")
    if cached is not None:
        return cached

    try:
        req = urllib.request.Request(
            "%s/%s/initiate-download" % (DATASET_BASE, dataset_id),
            data=b"{}",
            headers=_dataset_headers(),
            method="POST",
        )
        with urllib.request.urlopen(req, timeout=10) as resp:
            resp.read()
    except Exception:
        pass

    poll_req = urllib.request.Request(
        "%s/%s/poll-download" % (DATASET_BASE, dataset_id),
        headers=_dataset_headers(),
    )
    with urllib.request.urlopen(poll_req, timeout=15) as resp:
        envelope = json.loads(resp.read())
    url = envelope.get("data", {}).get("url")
    if not url:
        return []

    with urllib.request.urlopen(url, timeout=30) as resp:
        body = resp.read()

    text = body.decode("utf-8-sig", errors="replace")
    rows = list(_csv.DictReader(_io.StringIO(text)))
    _cache_put(namespace, "rows", rows)
    return rows


def fetch_dataset_geojson(dataset_id):
    """data.gov.sg dataset fetch (GeoJSON → parsed FeatureCollection dict)."""
    namespace = "dataset-geojson:%s" % dataset_id

    cached = _cache_get(namespace, "geojson")
    if cached is not None:
        return cached

    try:
        req = urllib.request.Request(
            "%s/%s/initiate-download" % (DATASET_BASE, dataset_id),
            data=b"{}",
            headers=_dataset_headers(),
            method="POST",
        )
        with urllib.request.urlopen(req, timeout=10) as resp:
            resp.read()
    except Exception:
        pass

    poll_req = urllib.request.Request(
        "%s/%s/poll-download" % (DATASET_BASE, dataset_id),
        headers=_dataset_headers(),
    )
    with urllib.request.urlopen(poll_req, timeout=15) as resp:
        envelope = json.loads(resp.read())
    url = envelope.get("data", {}).get("url")
    if not url:
        return {"type": "FeatureCollection", "features": []}

    with urllib.request.urlopen(url, timeout=30) as resp:
        body = resp.read().decode("utf-8-sig", errors="replace")

    parsed = json.loads(body)
    _cache_put(namespace, "geojson", parsed)
    return parsed


